var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"실망스럽구나.","JPN":"まことに残念だ。","ENG":"How disappointing.","TWN":"真讓人失望。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"마왕의 권능을 등에 업고도, 인간에게 패배하여 꼴사납게 도망쳐 오다니.","JPN":"魔王の権能があるにも関わらず、人間に敗北し見苦しく逃げてくるなど。","ENG":"Even with the Demon Lord's power, you lost to a human and fled.","TWN":"就算背靠魔王的權能，竟然還會敗給人類，狼狽地逃回來。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"면목 없군요. 인간들의 곁을 지키는 자가 악마일 줄은 몰랐습니다.","JPN":"面目ありません。人間たちのそばを守っている者が悪魔だとは知りませんでしたので。","ENG":"I apologize for my actions. I did not know that the one guarding the humans was a devil.","TWN":"真是無地自容。沒想到守護在人類身邊的竟然是魔鬼。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그래. 진작에 죽었어야 할 황금나무가 한낱 악마에게 쓰임 당하고 있었다는 건 뜻밖이군.","JPN":"ああ。とうに死んでいるはずの黄金の木が一介の悪魔に利用されていたのは予想外であるな。","ENG":"Yes. It is unexpected to hear that a mere devil is using the Golden Tree that should have died long ago as her own.","TWN":"哼哼，早該枯死的黃金樹竟然被一個魔鬼利用，真是出乎意料。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"하지만 지금은 밑동만 남은 그루터기일 뿐. 옛 황금나무의 위상에 비할 바는 아니겠지.","JPN":"だが、今は根本だけの切り株にすぎん。昔の黄金の木とは比べるまでもない。","ENG":"Nevertheless, all that remains of it is the stump. It is nothing compared to the Golden Tree of the old days.","TWN":"但現在它不過是個只剩木墩的殘骸，無法與昔日的黃金樹相提並論。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"물론입니다. 무엇보다 마왕께선 한낱 신성을 잃은 그 나무보다 더 본질적인 힘을 갖고 계시니까요.","JPN":"もちろんです。何より魔王は神聖さを無くしたあの木より、本質的な力をお持ちですから。","ENG":"Of course. Above all, the Demon Lord possesses greater intrinsic power than the tree that has lost its divinity.","TWN":"那是當然，魔王大人擁有的可是比那失去神性的枯樹更為本質的力量。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"동생이 직접 나설 일은 없을 거다. 내가 놈들을 짓밟고, 비루한 꼴로 연명하는 그 나무를 뿌리째 잘라낼 테니.","JPN":"妹が直接手を下すまでもない。余がやつらを踏みつけ、滑稽な姿で延命するあの木を根元ごと引き抜いてやろうではないか。","ENG":"My sister will not need to take care of them. I shall trample them myself and relieve the tree from its miserable state by cutting its roots.","TWN":"妹妹她是不會親自出手的。我會親自踏平那些廢物，把那棵苟延殘喘的樹連根拔起。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"인류의 보루를 찾아낸 상으로, 널 처벌하진 않으마.","JPN":"人類の要塞を探し出した褒美として、貴様への罰は取り消してやろう。","ENG":"As a reward for finding humanity's stronghold, I will not punish you.","TWN":"作為找到人類的獎勵，我將免除你的責罰。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"지금쯤 엘리시온에 묻힌 성자들이 망집이 되어 깨어났을 거다.","JPN":"そろそろエリシオンに埋まっている聖者たちが執念により目覚める頃だろう。","ENG":"By now, the Helgons buried in Elysion should have awakened as obsessions.","TWN":"此刻埋葬在艾利森的聖者們應該已經化作怨靈甦醒過來。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"넌 돌아가서 그것들에게 죽음보다 더한 고통을 주고…","JPN":"貴様は戻り、それらに死よりもつらい苦痛を与え……","ENG":"You, go back to them and give them a worse pain than death...","TWN":"你回去讓它們體驗比死亡更痛苦的折磨…"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"없애버려라.","JPN":"殺せ。","ENG":"Afterwards, get rid of them.","TWN":"然後，消滅它們。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"뜻밖이군요. 성자의 망집을 길들이면 마왕의 군세에도 제법 보탬이 될 텐데요.","JPN":"意外ですね。聖者たちを支配下におけば、魔王の軍勢にも役立つはずですが。","ENG":"How unexpected. For taming the obsessions of the Helgons could greatly aid your army.","TWN":"真是意外。如果能馴服聖者的怨靈，對魔王的軍隊也會有很大幫助吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"놈들에게 황금가지가 있는 한, 그 녀석들의 악기는 그저 잔재주일 뿐이다.","JPN":"やつらに黄金の枝があるかぎり、あやつらの楽器はただの小細工にすぎん。","ENG":"As long as the Stump has the Golden Branch, their instruments will be nothing but cheap tricks.","TWN":"只要擁有金枝，那些傢伙的樂器不過是些小把戲。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"잔말 말고 명령에 따라라, 삼하인.","JPN":"さっさと命令に従え、サウィン。","ENG":"Stop wasting your breath and do as you are ordered, Samhain.","TWN":"別廢話，按命令行事，薩溫。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"…알겠습니다. 그리 하죠.","JPN":"……承知しました。そういたしましょう。","ENG":"...Understood. As you command.","TWN":"…是，遵命。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"왕의 사도이시여.","JPN":"王の使徒よ。","ENG":"Oh, Apostle of the queen.","TWN":"王的使徒。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"부디 세상의 종말과 함께, 영광스러운 귀환을.","JPN":"どうか世界の終末とともに、光栄なる帰還を。","ENG":"Bring us a glorious return with the end of the world.","TWN":"願你與世界的終結一同，榮耀歸來。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"입구가 보입니다! 저 하수도 안에 저희가 찾는 적철이 있을 거예요!","JPN":"入口が見えます！　あの下水道の中に私たちが探している赤鉄があるはずです！","ENG":"I see the entrance! The Violarite we are looking for should be in those sewers!","TWN":"看到入口了！在那個下水道裡，我們要找的赤鐵應該就在裡面！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"역시 마물들이 지키고 있군요. 진입하려면 시선을 끄는 편이 좋겠습니다.","JPN":"やはり魔物たちが守っていますね。侵入するにはやつらの気を引いた方が良さそうです。","ENG":"As expected, the monsters are guarding it. We will need a distraction in order to gain entry.","TWN":"果然有怪物在守衛。要進去的話，最好引開它們的注意力。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"제가 유인할게요. 그동안 여러분은 안을 살펴봐주세요.","JPN":"私がおびき寄せます。その間にみなさんは中を探してください。","ENG":"I'll lure them away. In the meanwhile, you all should take a look inside.","TWN":"我來引開它們，你們趁機進去看看情況。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"저런 부류의 마물들은 두 다리로 따돌리긴 힘들 겁니다.","JPN":"あの種類の魔物を人の足で撒くのは難しいでしょう。","ENG":"Those types of monsters will be difficult to outrun with only two legs.","TWN":"那種類型的怪物，光靠兩條腿是甩不掉的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"괜찮다면, 이번엔 아이단과 함께 가시죠.","JPN":"よかったら、アイダンを使ってください。","ENG":"If it will be no trouble, take Aidan with you.","TWN":"如果可以的話，這次和艾丹一起去吧。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"윽… 말이요? 그치만 전 승마 같은 건 배운 적 없는데요?","JPN":"うっ……馬ですか？　でも、私は乗馬なんて教えてもらったことないですよ？","ENG":"Ngh... the horse? But I've never learned how to ride one.","TWN":"呃…騎馬嗎？可是我從來沒學過騎馬？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"괜찮습니다.","JPN":"大丈夫です。","ENG":"Not to worry.","TWN":"沒關係。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"이 친구는 술에 취해 인사불성이 된 제사장님도 자주 모셔왔으니까요.","JPN":"こいつは酒に酔ってフラフラになった祭祀長もよく乗せていました。","ENG":"As this one here has frequently brought even the piss-drunk High Priest home safe.","TWN":"這匹馬經常載著喝醉酒的祭司長，所以沒問題的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"좋아요! 해보죠!","JPN":"わかりました！　やってみましょう！","ENG":"All right! I'll give it a try!","TWN":"好！試試看吧！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"잘 부탁해요! 아이단!","JPN":"よろしくお願いします！　アイダン！","ENG":"Let's do this, Aidan!","TWN":"拜託了！艾丹！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"으앗?!","JPN":"わあっ！？","ENG":"Whoa?!","TWN":"呃啊啊？！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_HORSE_RUNNING_01"},{"id":"L45_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"마물들을 순식간에 지나쳤어요.","JPN":"あっという間に魔物たちの横を通り過ぎましたね。","ENG":"We passed the monsters in an instant.","TWN":"一躍就穿過了怪物們。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"마차에 묶여 있을 땐 몰랐는데, 엄청 빠르네요.","JPN":"馬車を引いていた時にはわかりませんでしたが、すごく速いです。","ENG":"I didn't know while he was tied to the carriage, but he's really fast.","TWN":"拉著馬車時沒感覺到，它跑得真快。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"지금이야. 안으로 들어가세.","JPN":"今だ。中に入ろう。","ENG":"Now! Let's all head inside.","TWN":"就是現在！進去吧！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"네…!","JPN":"はい……！","ENG":"Yes...!","TWN":"是…！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"찾았습니다! 적철이예요!","JPN":"ありました！　赤鉄です！","ENG":"I found some! It's Violarite!","TWN":"找到了！是赤鐵！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"좋아. 서둘러 추출하게!","JPN":"よし。急いで抽出するのだ！","ENG":"Very good. Now, we must extract it with haste!","TWN":"好，動作快點！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"진동…?","JPN":"揺れ……？","ENG":"Vibrations...?","TWN":"哪裡來的震動…？"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"안쪽에도 놈들이 있어요!","JPN":"中にもやつらがいます！","ENG":"There are monsters inside!","TWN":"裡面也有敵人！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"이쪽으로 옵니다!","JPN":"こっちに向かってきてます！","ENG":"They are charging toward here!","TWN":"往這邊來了！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"당황하지 말고 필요한 것부터 챙기게!","JPN":"慌てずに必要なものからまとめるんだ！","ENG":"Do not panic and grab what we need!","TWN":"不要慌，把東西都拿上！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"저건 내가 맡을 테니!","JPN":"あれは私に任せろ！","ENG":"I'll take care of this!","TWN":"那個交給我！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"지금이야! 놈들의 발이 묶였을 때 밖으로 나가자고!","JPN":"今だ！　やつらが動けない間に、外に出よう！","ENG":"NOW! Get out of here while they cannot move!","TWN":"就是現在！趁它們被困住的時候快走！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"따돌린 것 같군요.","JPN":"うまく撒いたようですね。","ENG":"I think we lost them.","TWN":"好像甩掉了。"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"그런데, 방금 던지신 폭탄은 뭐죠?","JPN":"でも、さっき投げた爆弾は何ですか？","ENG":"What was that bomb you threw?","TWN":"不過，剛才你扔的炸彈是什麼？"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"모르가나 아가씨가 만든 발명품일세.","JPN":"モルガナお嬢様が作った発明品だ。","ENG":"It's a bomb Miss Morgana invented.","TWN":"是莫甘娜小姐的發明。"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"지난 원정 때 악마가 쓰는 능력에서 영감을 받았다고 하더군.","JPN":"この前の遠征で悪魔が使っていた能力からヒントを得たらしい。","ENG":"She said she got inspired by the devil's ability on her last expedition.","TWN":"聽說是上次調查時從魔鬼的能力中得到的靈感。"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"대단하군요. 그 무식한 마물들의 발을 묶을 정도라니.","JPN":"すごいですね。あの恐ろしい魔物たちを足止めできるなんて。","ENG":"Amazing. And it's strong enough to immobilize those ignorant monsters.","TWN":"真厲害，竟然能困住那些凶狠的怪物。"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"놀랄 것도 없네. 발명하는 재주는 원래부터 다른 길잡이보다 뛰어난 분이셨으니.","JPN":"驚くことはない。発明能力は元々他の導き手より優れていた方だから。","ENG":"This is nothing to be surprised about. Her talent for inventing has always been the best compared to the other pathfinders.","TWN":"呵呵…小姐的發明才能本來就比其他引路人出色。"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"다들 무사하신가요?!","JPN":"みなさん、無事ですか！？","ENG":"Is everyone okay?","TWN":"大家都沒事吧？！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"마침 돌아오셨군요. 저희도 돌아 나가려던 참입니다.","JPN":"ちょうどお戻りになりましたね。私たちも出ようとしていたところです。","ENG":"You're just in time. We were also just about to go back out.","TWN":"你來得正好，我們也正準備出去。"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"잘 됐네요. 그럼 제가 마차까지 호위를…","JPN":"そうでしたか。じゃあ、私が馬車まで護衛を……","ENG":"That's good. Then I'll escort you all to the carriage–","TWN":"太好了，那我來護送你們到馬車…"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"으앗?! 지진…?!","JPN":"わあっ！？　地震……！？","ENG":"Whoa?! An earthquake...?!","TWN":"呃啊？！地震了…？！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"조심하세요!","JPN":"気をつけてください！","ENG":"Watch out!","TWN":"小心！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"마, 마물?!","JPN":"ま、魔物！？","ENG":"M-monsters?!","TWN":"怪…怪物？！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"이런…! 저 쐐기가 입구를 완전히 틀어막았어요!","JPN":"しまった……！　格子によって入口を封鎖されてしまいました！","ENG":"Dammit...! That wedge has completely blocked off the exit!","TWN":"糟了！入口完全被堵住了！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"이대로 갇혀선 안 되네! 화력으로 뚫게!","JPN":"このまま閉じ込められるわけにはいかん！　火力で押し通せ！","ENG":"Use firepower to break through! We cannot be trapped in here!","TWN":"不能就這樣被困住！開火打碎它！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"쐐기가 부서진 부위를 재생하고 있습니다! 틈이 보이질 않아요!","JPN":"格子が破壊したところを再生してます！　隙がありません！","ENG":"The wedge is regenerating its damaged areas! I don't see any way out!","TWN":"那個楔子一樣的東西正在修復破損的部分！沒有縫隙！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"곤란하게 됐군. 탈출구를 앞에 두고 매복에 당하다니.","JPN":"困ったな。逃げ道を目の前にして待ち伏せにやられるとは。","ENG":"This is not good. Getting ambushed right in front of the exit.","TWN":"傷腦筋，出口就近在眼前，卻遭到埋伏。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"찾았다…!","JPN":"見つけた……！","ENG":"Gotcha...!","TWN":"找到了…！"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"마물이 재생할 때마다 중앙의 빛나는 핵을 먼저 보호하고 있어요!","JPN":"魔物が再生するたび、中央で光る核を先に保護しています！","ENG":"When the monsters regenerate, they protect the glowing core first!","TWN":"每次怪物再生時，都會優先保護中間發光的核心！"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"그렇다면, 그곳이 놈의 약점일 가능성이 높겠군요.","JPN":"なら、そこがやつの弱点である可能性が高いですね。","ENG":"Then, it is highly likely that it is their weak point.","TWN":"那麼，那地方很可能是它的弱點！"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"계속 공격해주세요! 제가 틈을 노려볼게요!","JPN":"引き続き攻撃してください！　私が隙を狙ってみます！","ENG":"Keep attacking! I'll aim for the core!","TWN":"繼續攻擊！我來找機會！"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};